100 * max(
  1 - (rate(node_cpu_seconds_total{mode=~"idle"}[$__rate_interval]) or vector(0))
  ) by (instance)
* on (instance) group_left(node) (
  label_replace(
    max by (address, node) (kube_node_status_addresses{node=~".*", type="InternalIP"}),
    "instance", "$1:9100", "address", "(.*)"
  )
) or on() clamp_max(absent(node_cpu_seconds_total{node="offline"}),0)

100 * ((
  node_memory_MemTotal_bytes{job="node-exporter"}
-
  node_memory_MemFree_bytes{job="node-exporter"}
-
  node_memory_Buffers_bytes{job="node-exporter"}
-
  node_memory_Cached_bytes{job="node-exporter"}
) / node_memory_MemTotal_bytes{job="node-exporter"})
* on (instance) group_left(node) (
  label_replace(
    max by (address, node) (kube_node_status_addresses{node=~".*", type="InternalIP"}),
    "instance", "$1:9100", "address", "(.*)"
  )
) or on() clamp_max(absent(node_memory_Cached_bytes{node="offline"}),0)

